-- Enrichment marathon batch: Kit (formerly ConvertKit), Kittl, Kiwi IRC, Kiwix, Klaviyo, Klenty, Kling AI, KNIME

-- ── Kit (formerly ConvertKit) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Kit (formerly ConvertKit) is an email marketing and monetization platform built for online creators, offering automations, landing pages and paid newsletters.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $33/month)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$100-250 employees$q$, company_size),
  headquarters = COALESCE($q$Boise, Idaho, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Kit (ConvertKit) Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Kit (formerly ConvertKit) review: pricing tiers, automation and monetization features, pros and cons, and how it compares to Mailchimp, Beehiiv and Substack.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Kit, known for a decade as ConvertKit before its October 2024 rebrand, is an email marketing and audience-monetization platform built specifically for online creators, bloggers, YouTubers, podcasters and other independent professionals rather than traditional e-commerce or enterprise marketers. The company was founded in 2013 by Nathan Barry, who bootstrapped the business without taking venture capital, growing it into a business reportedly generating over 43.8 million dollars in annual recurring revenue and serving more than 60,000 paying customers by the mid-2020s. Kit is headquartered in Boise, Idaho, and operates as a remote-first company with a distributed team of roughly 100 to 150 employees spread across dozens of cities. The rebrand from ConvertKit to Kit in October 2024 was accompanied by a new visual identity, a simplified product narrative centered on creators reaching their first 1,000 subscribers and monetizing them, and a more generous free tier that now covers up to 10,000 subscribers. Architecturally, Kit differs from many general-purpose email service providers by organizing subscribers around flexible tags and segments rather than static mailing lists, which lets creators build a single audience and layer automations, sequences and campaigns on top of tag combinations instead of duplicating contacts across separate lists. The product centers on a visual, drag-and-drop automation builder for welcome sequences, tagging rules and sales funnels; unlimited customizable landing pages and opt-in forms; unlimited broadcast and newsletter sends; and audience segmentation based on engagement and behavior. Layered on top of this is a creator-monetization stack that differentiates Kit from generic ESPs: built-in paid newsletters and subscription tiers, digital product and course sales with a transaction fee (reported around 3.5 percent plus 30 cents on product sales), a virtual tip jar, and the Creator Network, a cross-promotion system where creators recommend each other's newsletters to new subscribers and share revenue, with Kit taking a reported 23.5 percent fee on paid recommendation earnings. Newer additions include Kit MCP, a Model Context Protocol integration that allows AI tools and agents to interact with a creator's Kit account and data. Pricing runs three tiers, all priced against a base subscriber count and scaling upward as a list grows: the Newsletter plan is free for up to 10,000 subscribers and includes unlimited landing pages, forms and broadcasts, one basic automation, and access to digital product and paid newsletter sales; the Creator plan starts at 33 dollars per month (or 390 dollars per year) for up to 1,000 subscribers and unlocks unlimited automations and sequences, A/B subject-line testing, polls and surveys, SMS marketing, custom branding, RSS-to-email campaigns and third-party app integrations; and Creator Pro starts at 66 dollars per month (or 790 dollars per year) for up to 1,000 subscribers, adding Subscriber Signals engagement and demographic data, engagement scoring, deliverability reporting, unlimited team seats, advanced A/B testing, Facebook custom audience sync, a newsletter referral program, and the ability to edit links after an email has already been sent. A 14-day free trial requiring no credit card is available on paid plans, alongside free concierge migration from competing platforms and an educational hub called Kit University. Kit's target audience is solo creators, newsletter writers, course creators and small content-driven businesses who want a platform purpose-built around growing and monetizing an audience rather than a generic marketing suite. Its most frequently cited competitors include Mailchimp, a broader small-business marketing platform with less creator-specific monetization tooling; Beehiiv and Substack, newsletter-first platforms with built-in publishing and monetization; ActiveCampaign and MailerLite, marketing-automation-focused ESPs; and Flodesk, a design-forward email tool aimed at creative small businesses. Kit differentiates through its tag-based data model, its deep native monetization features (paid newsletters, digital products, tip jars and creator cross-promotion), and its bootstrapped, profitable origin story, which it uses heavily in its brand positioning against venture-funded rivals.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '86565576-9938-418e-8b55-ba39e12ff033';

