-- ── Kiwi IRC ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Kiwi IRC is a free, open-source, browser-based IRC client that lets users join IRC networks instantly without installing any software.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Kiwi IRC Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Kiwi IRC review: open-source, browser-based IRC client features, self-hosting, and how it compares to The Lounge, IRCCloud and Mibbit.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Kiwi IRC is a free, open-source, browser-based IRC (Internet Relay Chat) client that traces its history back to a first commit in July 2011, making it one of the earlier modern web-based IRC clients still actively maintained. Rather than being built and sold by a single company, Kiwi IRC is developed as an open-source project (hosted on GitHub under the kiwiirc organization) written in JavaScript and built with Vue.js, webpack and Babel, and released under the GNU Affero General Public License version 3 (AGPLv3), which requires that modified versions run as a network service also make their source code available. The project serves two overlapping purposes: it is a self-hostable client that any individual, IRC network operator or community can download and deploy on their own web server or CDN, embedding it as a 'chat now' widget so visitors can join a channel instantly from a browser without installing a native IRC client such as HexChat, mIRC or Irssi; and it also operates a free public web gateway at kiwiirc.com that lets anyone connect to popular IRC networks directly from a browser using a shareable link, a format widely used by open-source projects, gaming communities and support channels to lower the barrier to entry for newcomers. Functionally, Kiwi IRC supports simultaneous connections to multiple IRC networks from a single interface, SSL/TLS-secured connections between the browser and IRC servers, standard IRC protocol features such as channel and room management, private messaging, user modes, and WHOIS lookups, plus several conveniences not found in older web IRC clients: a plugin architecture that supports file uploads and video calling (via Jitsi integration) directly inside a channel, multiple selectable interface themes (including a modern 'Relaxed' theme, a lightweight 'Basic' theme, and a dark 'CLI' theme styled after terminal IRC clients), a scripting interface for customizing client behavior, a real-time desktop notification system for new messages, and a responsive layout designed to work on both desktop and mobile browsers. The client can be deployed as a fully static set of files that work with any standard web server or CDN, which keeps self-hosting simple and cheap since no dedicated backend application server is required for many configurations, only a connection to an IRC network's own server infrastructure (directly or via a WebSocket-to-IRC gateway). Because Kiwi IRC is free and open source, there is no subscription pricing, license fee, or paid tier of any kind: organizations that self-host it pay only for their own web hosting infrastructure, and individual users of the public kiwiirc.com gateway pay nothing at all. Kiwi IRC's target audience includes open-source software projects and their support channels, gaming and hobbyist communities, IRC network operators who want to offer a zero-friction entry point on their website, and individual IRC users who prefer a lightweight browser-based client over installing dedicated desktop software. Its closest competitors and alternatives include The Lounge, a self-hosted, always-on web IRC client that acts like a bouncer to keep users connected even when their browser is closed; IRCCloud, a commercial hosted web and mobile IRC service offered on a freemium/paid subscription basis; Mibbit, an older and less actively developed web IRC client; Convos, another modern self-hosted web IRC client; and traditional native desktop clients such as HexChat, mIRC and Irssi. Kiwi IRC differentiates itself from IRCCloud primarily by being entirely free and self-hostable rather than a paid hosted service, and differentiates from The Lounge by emphasizing lightweight, static-file deployment and the instant no-signup public gateway experience that network operators can embed directly on their own websites for visitors who have never used IRC before.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2c54263d-78af-448f-8e86-9807365dad70';

