-- ── Kiwix ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Kiwix is a free, open-source offline reader that lets users download and browse Wikipedia and other web content without an internet connection.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Kiwix Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Kiwix review: how the free, open-source offline Wikipedia reader works, its ZIM file format, supported platforms, and alternatives like XOWA and WikiTaxi.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Kiwix is a free, open-source offline content reader founded in 2007 by Emmanuel Engelhart and Renaud Gaudin in Switzerland, with early support from Wikimedia CH, the Swiss chapter of the Wikimedia movement. The project began as a solution for distributing Wikipedia and other encyclopedic knowledge to people without reliable internet access, originally conceived for use cases such as ships at sea, prisons, rural schools and disaster-affected regions where connectivity is limited or unavailable. Kiwix operates as a not-for-profit organization funded primarily through donations and grants, including support from organizations such as the Wikimedia Foundation, and it does not display advertising or collect user data, positioning itself explicitly as a privacy-respecting, mission-driven alternative to commercial offline-content tools. At the technical core of Kiwix is the ZIM file format, a highly compressed, indexed archive format developed by the Kiwix team specifically for storing web content such as HTML pages, images and video while keeping file sizes small enough to fit on phones, USB drives, SD cards and low-cost hardware, all while remaining fully searchable offline through built-in full-text indexing. The Kiwix Reader application is available across Windows, macOS, Linux, Android and iOS, along with a browser extension and the Kiwix Serve command-line tool, which lets a single device host ZIM files over a local network so multiple nearby devices can browse the content through a normal web browser without any of them needing internet access. Through this reader and its companion library and catalog (accessible at library.kiwix.org), users can download pre-packaged ZIM archives of Wikipedia in dozens of languages and multiple size tiers ranging from text-only to full-media versions, plus Wikimedia sister projects including Wikisource, Wikiquote, Wikivoyage, Wikibooks and Wikiversity, as well as third-party educational and reference content such as Project Gutenberg books, Stack Exchange question-and-answer archives, TED talks, and modules from educational platforms like Khan Academy. Because the software and its underlying ZIM ecosystem are open source and released under open licenses, with code hosted publicly on GitHub under the kiwix organization and developed by a mix of paid staff and volunteer contributors worldwide, there is no subscription, paywall or premium tier of any kind. Organizations and individuals working in humanitarian and educational contexts also use companion hardware projects such as the Kiwix Hotspot, a Raspberry Pi-based offline Wi-Fi hotspot that broadcasts a local library of ZIM content to nearby phones and laptops without needing any internet backhaul connection, making it popular for refugee camps, remote schools and disaster response deployments. Kiwix's target users include humanitarian and NGO field workers, teachers and students in low-connectivity or no-connectivity regions, digital preservation and archiving advocates, off-grid and travel users, and privacy-conscious individuals who want an ad-free, tracking-free offline reference library. Because Kiwix operates as a nonprofit mission-driven project rather than a commercial SaaS product, it competes less on typical subscription metrics and more against other offline-knowledge distribution tools such as XOWA, an older Java-based offline Wikipedia application; WikiTaxi, a Windows-only offline Wikipedia reader; and DVD or USB-based offline encyclopedia distributions, as well as related offline-education infrastructure projects like RACHEL from World Possible and Internet-in-a-Box. Kiwix differentiates itself through its open ZIM file format, which other tools and hardware projects can also read and build on, its broad content library extending well beyond Wikipedia alone, its long operating history dating back to 2007, and its close ties to the Wikimedia community that give it particular credibility for offline encyclopedic content.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '650e05bf-0756-4e0c-83db-dabfb42d361a';

