INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Visual Automations$q$, $q$A drag-and-drop automation builder for welcome sequences, tagging rules, and multi-step sales and nurture funnels.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Landing Pages and Forms$q$, $q$Unlimited customizable opt-in forms and landing pages available on every plan, including the free tier.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Paid Newsletters and Subscriptions$q$, $q$Built-in tools to monetize content directly through monthly, quarterly or annual paid subscription tiers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Digital Product Sales$q$, $q$Sell digital downloads, courses and products directly through Kit, subject to a transaction fee on the free plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Creator Network$q$, $q$A cross-promotion system where creators recommend each other's newsletters to new subscribers and share revenue.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Tag-Based Segmentation$q$, $q$Subscribers are organized by flexible tags rather than static lists, avoiding duplicate contacts across campaigns.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$SMS Marketing$q$, $q$Text-message campaigns available starting on the Creator plan for reaching subscribers beyond email.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Subscriber Signals and Deliverability Reporting$q$, $q$Engagement scoring and demographic insight tools available on the Creator Pro plan, plus deliverability analytics.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Generous free plan covering up to 10,000 subscribers with unlimited sends, forms and landing pages$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Built-in creator monetization tools (paid newsletters, digital products, tip jar) rarely bundled by general ESPs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Flexible tag-based segmentation avoids duplicating contacts across multiple lists$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Bootstrapped, profitable company with over a decade of creator-focused product development$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Free migration support and educational resources (Kit University) for creators switching platforms$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Pricing scales quickly with subscriber count on the Creator and Creator Pro tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Automation and reporting depth is lighter than enterprise marketing suites like ActiveCampaign or Klaviyo$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Digital product sales and paid recommendations carry transaction fees$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Fewer e-commerce-specific integrations compared to Klaviyo or Omnisend$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Email and landing page design customization is more basic than design-first tools like Flodesk$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Why did ConvertKit change its name to Kit?$q$, $q$ConvertKit rebranded to Kit in October 2024 as part of a broader repositioning around helping creators grow and monetize an audience, alongside a new free plan structure and visual identity.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Is Kit free to use?$q$, $q$Yes. The Newsletter plan is free for up to 10,000 subscribers and includes unlimited landing pages, forms, broadcasts and one basic automation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Does Kit charge fees on digital product or newsletter sales?$q$, $q$Kit applies transaction fees on digital product sales and on Creator Network paid recommendation revenue; exact rates vary by plan and feature.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Who founded Kit and when?$q$, $q$Kit was founded in 2013 by Nathan Barry as ConvertKit and was built as a bootstrapped company without outside venture capital.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$What is the Kit Creator Network?$q$, $q$It is a cross-promotion feature that lets creators recommend each other's newsletters to subscribers, sharing revenue on paid recommendations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$How does Kit differ from Mailchimp?$q$, $q$Kit uses tag-based subscriber segmentation and bundles creator monetization tools like paid newsletters and digital products, while Mailchimp is a broader small-business marketing suite.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Newsletter Monetization$q$, $q$Independent writers launch paid subscription newsletters and manage free-to-paid subscriber conversion.$q$, $q$Independent journalists and newsletter writers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Digital Product and Course Sales$q$, $q$Educators sell digital downloads and online courses directly to their email audience without separate storefront tools.$q$, $q$Online educators and coaches$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Multi-Platform Audience Building$q$, $q$Creators use tagging and segmentation to unify audiences collected across YouTube, podcasts and social platforms into one email list.$q$, $q$YouTubers and podcasters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Newsletter (Free)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 10,000 subscribers","Unlimited landing pages and forms","Unlimited broadcasts","1 basic automation","Tagging and segmentation","Digital product sales (transaction fees apply)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Creator$q$, $q$$33/month$q$, $q$Monthly (also available at $390/year, for up to 1,000 subscribers)$q$, NULL, $q$["Everything in Newsletter","Unlimited automations and sequences","A/B subject line testing","SMS marketing","Polls and surveys","Custom branding removal","RSS-to-email campaigns","App integrations","Kit MCP"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$Creator Pro$q$, $q$$66/month$q$, $q$Monthly (also available at $790/year, for up to 1,000 subscribers)$q$, NULL, $q$["Everything in Creator","Subscriber Signals engagement and demographic data","Engagement scoring","Deliverability reporting","Unlimited team seats","Advanced A/B testing","Facebook custom audience sync","Newsletter referral system","Edit links after sending"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kit is an email marketing platform purpose-built for online creators, rebranded from ConvertKit in October 2024 after more than a decade under its original name. Founded in 2013 by Nathan Barry, the company grew as a bootstrapped, profitable business focused specifically on bloggers, newsletter writers, course creators and other independent professionals rather than general small-business marketing.$q$, $q$Unlike list-based email tools, Kit organizes subscribers using tags and segments, letting creators build a single unified audience and apply automations, sequences and campaigns based on tag combinations rather than duplicating contacts across separate mailing lists. This data model underpins the platform's automation builder, landing pages, forms and broadcast tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kit's core toolkit includes a visual drag-and-drop automation builder for sequences and funnels, unlimited landing pages and opt-in forms, unlimited broadcast sends, and tag-based segmentation. On top of these fundamentals, Kit layers creator-specific monetization features not commonly bundled by general-purpose email tools.$q$, $q$These monetization tools include paid newsletters and subscription tiers, digital product and course sales (with a transaction fee on product sales), a virtual tip jar, and the Creator Network, which lets creators cross-promote and earn revenue by recommending each other's newsletters to new subscribers. Kit MCP, a newer addition, lets AI agents and tools connect to a creator's Kit account via the Model Context Protocol.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kit offers three pricing tiers that scale with subscriber count. The Newsletter plan is free for up to 10,000 subscribers and includes unlimited landing pages, forms and broadcasts plus one basic automation. The Creator plan starts at 33 dollars per month for up to 1,000 subscribers and adds unlimited automations, SMS marketing, A/B testing and integrations.$q$, $q$Creator Pro starts at 66 dollars per month for up to 1,000 subscribers and adds engagement analytics, deliverability reporting, unlimited team seats and advanced testing tools. Both paid plans offer a 14-day free trial with no credit card required, and pricing increases as a creator's subscriber count grows beyond the base tier.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
