INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('86565576-9938-418e-8b55-ba39e12ff033', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$AI Image Generation$q$, $q$Generate original artwork and design elements from text prompts directly inside the editor.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Vectorizer$q$, $q$Convert raster images and photos into clean, editable vector paths suitable for print and cutting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$AI Background Remover$q$, $q$Automatically remove backgrounds from uploaded images for use in designs and mockups.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$3D Text and Effects$q$, $q$Add depth, texture and lighting effects to typography for eye-catching merch and branding designs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Template and Mockup Library$q$, $q$A large collection of templates, fonts and product mockups (apparel, packaging, posters) for fast design assembly.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Brand Kits$q$, $q$Store brand colors, fonts and logos for consistent reuse across multiple design projects.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Commercial Licensing$q$, $q$Paid plans bundle commercial usage rights for selling physical products printed with Kittl designs.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Vector-Native Export$q$, $q$Export designs as scalable vector files suited for large-format printing rather than raster-only output.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Vector-native AI output better suited for print and merchandise than raster-only competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Large template and mockup library tailored to apparel, packaging and print-on-demand use cases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Well-funded company (~$61.5M raised) investing heavily in AI design features$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Commercial licensing bundled directly into paid subscription tiers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Affordable entry-level Pro plan compared to full Adobe Creative Cloud subscriptions$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Free plan is limited to personal, non-commercial use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$AI generation credits are capped by plan and can run out with heavy use$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Less established brand recognition and template breadth than Canva$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Business/team pricing requires contacting sales rather than transparent self-serve rates$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Primarily optimized for merch/print use cases rather than general marketing design like social media suites$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Who founded Kittl and when?$q$, $q$Kittl was founded in 2020 by Nicolas Heymann and Tobias Saul and is headquartered in Berlin, Germany.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Is Kittl free to use?$q$, $q$Kittl offers a free plan for personal, non-commercial use with limited exports; commercial licensing requires a paid Pro, Expert or Business plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$How much does Kittl cost?$q$, $q$Kittl's Pro plan starts at 10 dollars per month billed annually, and the Expert plan starts at 24 dollars per month billed annually; Business pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$How is Kittl different from Canva?$q$, $q$Kittl emphasizes vector-native AI-generated output and merchandise/print-specific templates and mockups, while Canva is a broader general-purpose design tool.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Does Kittl support commercial use for print-on-demand sellers?$q$, $q$Yes, paid Kittl plans bundle commercial licensing that permits selling physical products printed with designs made on the platform, up to plan-specific limits.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$How much funding has Kittl raised?$q$, $q$Kittl has raised a reported total of about 61.5 million dollars, including a 36 million dollar Series B led by IVP in January 2024.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Print-on-Demand Merchandise Design$q$, $q$Sellers create t-shirt, apparel and packaging artwork using vector-native templates and mockups for print production.$q$, $q$Etsy and print-on-demand entrepreneurs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Brand Identity Design$q$, $q$Small businesses and freelancers build logos, brand kits and marketing collateral without a dedicated design team.$q$, $q$Small business owners and freelance designers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$AI-Assisted Artwork Creation$q$, $q$Designers generate original artwork and text effects with AI tools to speed up creative concepting.$q$, $q$Graphic designers and creative agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Personal, non-commercial use","Limited exports","Access to core editor and basic templates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Pro$q$, $q$$10/month$q$, $q$Billed annually ($15/month billed monthly)$q$, NULL, $q$["Commercial licensing","Unlimited vector exports","AI generation credits for regular use","Access to full template library"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Expert$q$, $q$$24/month$q$, $q$Billed annually ($30/month billed monthly)$q$, NULL, $q$["Everything in Pro","Higher AI credit allowance","Expanded commercial licensing limits","Suited for high-volume or multi-brand use"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$Business$q$, $q$Custom pricing$q$, $q$Contact sales$q$, NULL, $q$["Team seats for multiple designers","Enhanced licensing beyond Expert limits","Agency and company collaboration features"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kittl is a browser-based, AI-first design platform founded in 2020 by Nicolas Heymann and Tobias Saul and headquartered in Berlin, Germany. The company has raised roughly 61.5 million dollars across funding rounds, including a 2024 Series B led by IVP, to expand its AI design tools globally.$q$, $q$The platform is built around merchandise, apparel, branding and print use cases, emphasizing vector-native output over raster-only graphics so that designs remain crisp and editable at large print sizes, which differentiates it from general-purpose design tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kittl combines a traditional vector and layout editor with generative AI tools including AI image generation, an image vectorizer, an AI background remover, and 3D text and effects. A large library of templates, fonts, graphics and product mockups helps non-designers assemble sellable artwork quickly.$q$, $q$Brand kit functionality lets teams store and reuse colors, fonts and logos across projects, while bundled commercial licensing terms on paid plans let creators legally sell physical products printed with Kittl-made designs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kittl offers a Free plan for personal, non-commercial use, a Pro plan at 10 dollars per month billed annually with commercial licensing and unlimited vector exports, and an Expert plan at 24 dollars per month billed annually with higher AI credit and export allowances for high-volume users.$q$, $q$A Business plan for agencies and teams with multiple designers is available on custom, quote-based pricing that scales licensing and seats to organizational needs. Monthly billing is available on Pro and Expert at a higher per-month rate than the annual option.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
