INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3823f80c-7e1b-4a40-b37f-ad8fde45d0d9', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Multi-Network Connections$q$, $q$Connect to multiple IRC networks simultaneously from a single browser-based interface.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$SSL/TLS Secured Connections$q$, $q$Secure encrypted connections between the browser client and IRC servers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Self-Hosted or Public Gateway$q$, $q$Deploy Kiwi IRC on your own web server or use the free public gateway at kiwiirc.com.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Plugin Support$q$, $q$Extend functionality with plugins for file uploads and Jitsi-based video calling inside channels.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Multiple Themes$q$, $q$Choose between Relaxed, Basic and CLI dark themes to customize the chat interface.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Scripting Interface$q$, $q$Customize client behavior through a built-in scripting interface for advanced users.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Static Deployment$q$, $q$Runs as fully static files compatible with any standard web server or CDN for simple self-hosting.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Real-Time Notifications$q$, $q$Desktop notifications alert users to new messages and mentions in real time.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Completely free and open source with no subscription costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$No installation required; runs directly in any modern browser$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Self-hostable as static files, making deployment cheap and simple$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Supports multiple simultaneous IRC network connections$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Active open-source project with plugin extensibility for file sharing and video calls$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Requires self-hosting or reliance on the public gateway rather than a managed cloud service$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Lacks persistent bouncer-style always-connected functionality found in tools like The Lounge or IRCCloud$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$No official mobile app; relies on responsive browser design$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Documentation and support are community-driven rather than commercially backed$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Less actively marketed and updated compared to commercial hosted IRC alternatives$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Is Kiwi IRC free to use?$q$, $q$Yes, Kiwi IRC is completely free and open source, both for self-hosting and for using the public web gateway at kiwiirc.com.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Do I need to install anything to use Kiwi IRC?$q$, $q$No, Kiwi IRC runs entirely in a web browser, so no desktop or mobile app installation is required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Can I self-host Kiwi IRC?$q$, $q$Yes, Kiwi IRC can be deployed as static files on your own web server or CDN, making it suitable for network operators who want to embed a chat client on their site.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$What license does Kiwi IRC use?$q$, $q$Kiwi IRC is released under the GNU Affero General Public License version 3 (AGPLv3).$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$How does Kiwi IRC differ from The Lounge or IRCCloud?$q$, $q$Kiwi IRC emphasizes lightweight static deployment and an instant no-signup gateway, while The Lounge focuses on always-on bouncer-style connections and IRCCloud is a paid hosted service.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Does Kiwi IRC support video calling?$q$, $q$Yes, through plugin support that integrates Jitsi-based video calling directly inside channels.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Open-Source Project Support Channels$q$, $q$Projects embed a Kiwi IRC widget on their website so visitors can join the support channel instantly without installing software.$q$, $q$Open-source software maintainers and communities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$IRC Network Onboarding$q$, $q$Network operators offer a zero-friction browser-based entry point to attract newcomers unfamiliar with traditional IRC clients.$q$, $q$IRC network operators and administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Lightweight Personal IRC Access$q$, $q$Individual users connect to favorite IRC networks quickly from any browser without installing dedicated desktop software.$q$, $q$IRC hobbyists and casual users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code available on GitHub","Deploy on your own web server or CDN","AGPLv3 licensed","Plugin and theme support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$Public Web Gateway$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Instant browser access at kiwiirc.com","No installation or account required","Connect to popular IRC networks"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kiwi IRC is a free, open-source, browser-based IRC client with roots dating to 2011. It is developed as a community open-source project rather than by a single company, built with Vue.js and released under the AGPLv3 license, and hosted on GitHub under the kiwiirc organization.$q$, $q$The project serves both as a self-hostable client that IRC network operators can embed on their own websites, and as a free public web gateway at kiwiirc.com that lets anyone join popular IRC networks instantly from a browser without installing native IRC software.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kiwi IRC supports simultaneous connections to multiple IRC networks, SSL/TLS-secured connections, and standard IRC features like channel management, private messaging and user modes. A plugin system adds file uploads and Jitsi-based video calling inside channels.$q$, $q$Additional conveniences include multiple interface themes, a scripting interface for customization, real-time desktop notifications, and a responsive layout for mobile and desktop browsers. The client can be deployed as fully static files on any standard web server or CDN.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kiwi IRC is completely free and open source with no subscription or license fee of any kind. Organizations that self-host the client only pay for their own web hosting infrastructure.$q$, $q$Individual users of the public kiwiirc.com gateway can connect to supported IRC networks at no cost, with no account or payment required to start chatting.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2c54263d-78af-448f-8e86-9807365dad70', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$ZIM File Format$q$, $q$A highly compressed, indexed archive format built for storing and fully searching offline web content.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Cross-Platform Reader Apps$q$, $q$Native apps for Windows, macOS, Linux, Android and iOS, plus a browser extension.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Offline Wikipedia Library$q$, $q$Download Wikipedia in dozens of languages and multiple size tiers, from text-only to full-media archives.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Kiwix Serve$q$, $q$A command-line tool for hosting ZIM files over a local network so nearby devices can browse without internet access.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Wikimedia Sister Projects$q$, $q$Offline access to Wikisource, Wikiquote, Wikivoyage, Wikibooks and Wikiversity content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Third-Party Content Catalog$q$, $q$Additional offline archives including Project Gutenberg, Stack Exchange, TED talks and Khan Academy modules.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Kiwix Hotspot$q$, $q$A Raspberry Pi-based offline Wi-Fi hotspot for broadcasting a local content library without internet backhaul.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$No Ads or Tracking$q$, $q$Kiwix displays no advertising and does not collect user data, funded instead through donations and grants.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Completely free, open source, and ad-free with no data collection$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Works fully offline, ideal for low-connectivity or disaster-affected regions$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Broad content library beyond Wikipedia, including books, courses and Q&amp;A archives$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Available across nearly every major platform (Windows, macOS, Linux, Android, iOS)$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Open ZIM file format supported by other tools and hardware projects$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Content archives (especially full-media Wikipedia) can require significant storage space$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Content is only as current as the last downloaded ZIM snapshot, not live-updating$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Interface is utilitarian and less polished than commercial reference apps$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Setting up local network hosting (Kiwix Serve) requires some technical familiarity$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Smaller ecosystem and community support compared to major commercial apps$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Is Kiwix really free?$q$, $q$Yes, Kiwix is completely free, open source, and funded through donations and grants, with no subscription or premium tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$What is a ZIM file?$q$, $q$A ZIM file is a highly compressed, indexed archive format developed by Kiwix for storing and fully searching offline web content such as Wikipedia.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Can I use Kiwix without an internet connection?$q$, $q$Yes, once a ZIM content archive is downloaded, Kiwix Reader works entirely offline with full search functionality.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$What platforms does Kiwix support?$q$, $q$Kiwix Reader is available for Windows, macOS, Linux, Android and iOS, along with a browser extension.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Who founded Kiwix?$q$, $q$Kiwix was founded in 2007 by Emmanuel Engelhart and Renaud Gaudin in Switzerland, with early support from Wikimedia CH.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$What content besides Wikipedia is available on Kiwix?$q$, $q$Kiwix's catalog includes Wikimedia sister projects, Project Gutenberg books, Stack Exchange archives, TED talks and Khan Academy modules.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Offline Access in Low-Connectivity Regions$q$, $q$NGOs and educators distribute offline Wikipedia and educational content to schools and communities without reliable internet.$q$, $q$Humanitarian and NGO field workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Emergency and Travel Preparedness$q$, $q$Individuals download reference archives to their devices for use during travel, outages or emergencies.$q$, $q$Travelers and preppers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Digital Preservation and Archiving$q$, $q$Archivists and researchers use the open ZIM format to preserve and distribute large web-based knowledge collections.$q$, $q$Digital preservation advocates and researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$Kiwix Reader$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Available on Windows, macOS, Linux, Android and iOS","Access to full ZIM content catalog","Offline full-text search","Kiwix Serve for local network hosting","No ads or data collection"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kiwix is a free, open-source offline content reader founded in 2007 by Emmanuel Engelhart and Renaud Gaudin in Switzerland, with early support from Wikimedia CH. It was created to distribute Wikipedia and other reference content to people without reliable internet access, such as those on ships, in prisons, or in remote or disaster-affected regions.$q$, $q$The organization operates as a not-for-profit funded through donations and grants, does not display ads, and does not collect user data. Its technical foundation is the ZIM file format, a highly compressed, searchable archive format built specifically for offline web content distribution.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Kiwix Reader is available on Windows, macOS, Linux, Android and iOS, plus a browser extension and the Kiwix Serve tool for hosting ZIM files over a local network so multiple nearby devices can browse without internet access.$q$, $q$Through its library and catalog, users can download Wikipedia in dozens of languages, Wikimedia sister projects like Wikisource and Wikivoyage, and third-party content such as Project Gutenberg books, Stack Exchange archives, TED talks and Khan Academy modules. Companion hardware like the Kiwix Hotspot broadcasts offline content locally via Wi-Fi.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kiwix is entirely free, open source, and has no subscription, paywall or premium tier. All reader apps, the ZIM content catalog, and companion tools are free to download and use.$q$, $q$As a donation-funded nonprofit, Kiwix accepts voluntary contributions and grants (including from organizations such as the Wikimedia Foundation) to sustain development, but no payment is required to access or use any part of the platform.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('650e05bf-0756-4e0c-83db-dabfb42d361a', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Unified Customer Data Platform$q$, $q$Combines purchase history, browsing behavior and engagement data into a single real-time customer profile.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Email and SMS/MMS Marketing$q$, $q$Drag-and-drop email builder plus SMS and MMS messaging with compliance tooling for opt-ins.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$WhatsApp and Push Notifications$q$, $q$Multichannel messaging extending beyond email and SMS to WhatsApp business messaging and mobile push.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Predictive Analytics$q$, $q$Predicts customer lifetime value, churn risk and estimated next order date from unified profile data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Triggered Automations$q$, $q$Pre-built flows for abandoned cart, browse abandonment, post-purchase and win-back campaigns.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Klaviyo AI and Composer$q$, $q$Generative AI tools for subject lines, copy and creative asset generation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$AI Agents (Marketing Agent, Customer Agent)$q$, $q$Agentic AI tools that automate campaign planning and provide 24/7 AI-driven customer service.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$E-commerce Platform Integrations$q$, $q$Native integrations with Shopify, WooCommerce, BigCommerce and PrestaShop for real-time data sync.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Deep, real-time e-commerce data integration unmatched by generic email tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Predictive analytics (LTV, churn risk) built directly into segmentation and automation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Combines email, SMS, MMS, WhatsApp and push in one unified platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Rapidly expanding AI and agentic feature set (Composer, Marketing Agent, Customer Agent)$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Public company with strong financial backing and continuous product investment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Pricing based on active profiles can become expensive as a contact list grows$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Steeper learning curve than simpler email tools due to platform depth$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$SMS/MMS credit pricing adds complexity on top of base subscription cost$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Primarily optimized for e-commerce, less suited to non-retail businesses$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$No broadly advertised annual-commitment discount to lower per-month costs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Is Klaviyo free to use?$q$, $q$Yes, Klaviyo offers a free plan for up to 250 active profiles with 500 email sends per month and a small SMS/MMS credit allotment.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$How is Klaviyo priced?$q$, $q$Klaviyo prices its Email and Email plus SMS plans based on the number of active profiles (engaged contacts), with cost increasing as that count grows.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Who founded Klaviyo and when did it IPO?$q$, $q$Klaviyo was founded in 2013 by Andrew Bialecki and Ed Hallen and went public on the NYSE under ticker KVYO on September 20, 2023.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$What e-commerce platforms does Klaviyo integrate with?$q$, $q$Klaviyo has native integrations with Shopify, WooCommerce, BigCommerce and PrestaShop, among others.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$What AI features does Klaviyo offer?$q$, $q$Klaviyo AI provides content generation, Composer creates creative assets, and agentic tools like Marketing Agent and Customer Agent automate campaign planning and customer service.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$How does Klaviyo differ from Mailchimp?$q$, $q$Klaviyo emphasizes deep real-time e-commerce data integration and predictive analytics, while Mailchimp is a broader small-business marketing suite with less native e-commerce depth.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Abandoned Cart Recovery$q$, $q$E-commerce brands automatically trigger personalized email and SMS flows when shoppers leave items in their cart.$q$, $q$Direct-to-consumer e-commerce brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Predictive Customer Segmentation$q$, $q$Marketing teams segment audiences by predicted lifetime value and churn risk for targeted campaigns.$q$, $q$E-commerce marketing and CRM teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$AI-Automated Customer Service$q$, $q$Support teams use Customer Agent to automate routine customer inquiries around the clock.$q$, $q$E-commerce customer support teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["Up to 250 active profiles","500 email sends per month","Small SMS/MMS credit allotment","Basic reporting and dashboards","Customer Hub and Helpdesk (basic)","Email support (first 60 days)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Email$q$, $q$From $20/month$q$, $q$Monthly, scales with active profile count$q$, NULL, $q$["Unlimited email sends","Advanced segmentation and automation","A/B testing","Predictive analytics","Reporting and benchmarks"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Email + SMS$q$, $q$From $35/month$q$, $q$Monthly, scales with active profile count$q$, NULL, $q$["Everything in Email","SMS and MMS messaging","Included message credit allotment","Compliance and opt-in tooling"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Contact sales$q$, NULL, $q$["Custom active profile volume","Dedicated support and onboarding","Advanced data and analytics add-ons","Professional services available"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Klaviyo is a publicly traded (NYSE: KVYO) customer engagement and data platform founded in 2013 in Boston by Andrew Bialecki and Ed Hallen. The company went public in September 2023, raising approximately 576 million dollars at a roughly 9.2 billion dollar valuation, and today serves around 196,000 merchant customers, most of them e-commerce sellers on platforms like Shopify.$q$, $q$Klaviyo positions itself as an omnichannel customer platform rather than a simple email tool, combining email, SMS, MMS, WhatsApp and push notifications with a built-in customer data platform that unifies purchase history and engagement data into a single customer profile.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Klaviyo integrates directly with e-commerce storefronts to pull real-time order and browsing data, powering triggered automations like abandoned cart and post-purchase flows, plus predictive analytics such as customer lifetime value and churn risk, all built on a unified customer profile.$q$, $q$Since 2023 the platform has added significant AI capability, including Klaviyo AI for content generation, a Composer tool for creative assets, and agentic tools like Marketing Agent for campaign automation and Customer Agent for AI-driven customer service, alongside a Customer Hub and Helpdesk for support.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Klaviyo prices plans by active profile count rather than flat per-seat pricing. The Free plan covers up to 250 active profiles; the Email plan starts around 20 dollars per month and scales with contact count; and the Email plus SMS plan starts around 35 dollars per month with bundled message credits.$q$, $q$Larger organizations can move to a custom-priced Enterprise tier with optional add-ons like Data and Analytics, Composer AI and Customer Agent AI, negotiated directly with Klaviyo's sales team. There are no broadly advertised annual-commitment discounts.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d3223547-1bc9-472d-8449-260dc6b88988', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
