INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Multichannel Cadences$q$, $q$Multi-step outreach sequences combining email, calls, SMS, WhatsApp and LinkedIn from a single workspace.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Parallel and Power Dialer$q$, $q$Built-in cold-calling dialer with number auto-rotation and reputation management.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$AI Call Intelligence$q$, $q$Automatic voicemail/IVR detection, call outcome tracking, live transcription and coaching summaries.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$AI Objection Detection and Battlecards$q$, $q$Real-time AI guidance during calls to help reps handle objections and follow talk tracks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Account-Based Selling$q$, $q$Rep360 account view plus account prioritization and coverage tools for targeted outbound.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$CRM Integrations$q$, $q$Bidirectional sync with Salesforce, HubSpot, Pipedrive and Zoho.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Email Deliverability Tools$q$, $q$Custom domain tracking, send-volume throttling and randomized intervals to protect sender reputation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Personalization and Testing$q$, $q$Merge fields, Liquid templating, A/B testing and reply sentiment optimization.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Lower per-seat pricing than enterprise competitors like Outreach and Salesloft$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Combines email, calling, SMS, WhatsApp and LinkedIn in a single cadence engine$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Extensive AI-driven call coaching and intelligence features on higher tiers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Fast reported implementation timelines (one to two days)$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$14-day free trial with no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Calling minutes are capped by plan, with add-on dialer costs for higher volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Advanced AI coaching and account-based selling features reserved for the top Plus tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Smaller ecosystem and brand recognition compared to Outreach and Salesloft$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Per-user pricing on Growth and Plus tiers can add up for larger sales teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Funding history is less established than larger, longer-VC-backed competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Who founded Klenty and when?$q$, $q$Klenty was founded in 2016 by Vengat Krishnaraj (CEO) and Praveen Kumar (CRO).$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Where is Klenty headquartered?$q$, $q$Klenty is headquartered in Palo Alto, California, with its product and engineering team based in Chennai, India.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$How much does Klenty cost?$q$, $q$Klenty's Starter plan starts at 50 dollars per month billed annually, with Growth at 70 dollars per user per month and Plus at 99 dollars per user per month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Does Klenty offer a free trial?$q$, $q$Yes, Klenty offers a 14-day free trial with no credit card required, including an allotment of emails to prospects.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$What channels does Klenty support for outreach?$q$, $q$Klenty supports email, cold calling, SMS, WhatsApp and LinkedIn social selling within unified multichannel cadences.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$How does Klenty compare to Outreach and Salesloft?$q$, $q$Klenty is generally positioned as a lower-priced alternative with faster implementation, while Outreach and Salesloft are larger, more established enterprise sales engagement platforms.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Multichannel Outbound Prospecting$q$, $q$SDR teams run coordinated email, call and social sequences to book more meetings without manual tool-switching.$q$, $q$B2B sales development representatives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$AI-Assisted Cold Calling$q$, $q$Sales reps use the parallel dialer and AI call intelligence to increase call volume and improve conversion quality.$q$, $q$B2B account executives and SDR teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Account-Based Sales Execution$q$, $q$Revenue teams prioritize and track engagement across target accounts using the Rep360 and account-based selling tools.$q$, $q$Enterprise sales and revenue operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Starter$q$, $q$$50/month$q$, $q$Billed annually$q$, NULL, $q$["Up to 15,000 monthly contacts","75,000 monthly emails","Email deliverability tools","Sales ops and analytics","API and Zapier integrations","A/B testing and reply optimization"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Growth$q$, $q$$70/user/month$q$, $q$Billed annually$q$, NULL, $q$["Everything in Starter","200 minutes of calling included","Cold calling and dialer","AI voicemail/IVR detection","Multichannel outreach (SMS, WhatsApp, LinkedIn)","CRM integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Plus$q$, $q$$99/user/month$q$, $q$Billed annually$q$, NULL, $q$["Everything in Growth","1,000 minutes of calling included","Account-based selling suite","AI battlecards and objection detection","Live call transcription and coaching summaries","AI call scorecards"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$Parallel and Power Dialer Add-On$q$, $q$$45/user/month$q$, $q$Add-on to any plan$q$, NULL, $q$["Higher-volume outbound calling capacity","Available on top of Starter, Growth or Plus"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Klenty is a sales engagement platform founded in 2016 by Vengat Krishnaraj and Praveen Kumar, headquartered in Palo Alto, California, with its product and engineering team based in Chennai, India. The company grew largely bootstrapped before reportedly raising a seed round of about 5.53 million dollars around September 2025.$q$, $q$Klenty targets B2B sales teams that need to run high-volume, personalized outbound prospecting across multiple channels without stitching together separate point tools for email, calling and social outreach.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's core is 'cadences,' multi-step multichannel sequences spanning email, calls, SMS, WhatsApp and LinkedIn, synced bidirectionally with CRMs like Salesforce, HubSpot, Pipedrive and Zoho. A built-in parallel and power dialer includes number auto-rotation and reputation management.$q$, $q$AI features layered on top include voicemail and IVR detection, call outcome tracking, live transcription and coaching summaries, objection detection, AI battlecards and call scorecards, plus an account-based selling layer for prioritizing and tracking engagement at the account level.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Klenty offers three per-user subscription tiers billed annually: Starter at 50 dollars per month, Growth at 70 dollars per user per month with 200 calling minutes, and Plus at 99 dollars per user per month with 1,000 calling minutes and the full AI coaching suite.$q$, $q$A Parallel and Power Dialer add-on is available for 45 dollars per user per month, and all plans include a 14-day free trial requiring no credit card.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6ea439db-0c8a-4902-ad45-6e5684c0f9ee', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Text-to-Video Generation$q$, $q$Generate short video clips directly from written text prompts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Image-to-Video Generation$q$, $q$Animate still images into video clips using them as a generation reference.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Multi-Shot Director Mode$q$, $q$Kling 3.0 can plan and generate up to six distinct shots within a single clip while maintaining continuity.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$4K and High Frame Rate Output$q$, $q$Kling 3.0 Turbo generates natively at 4K resolution and up to 60fps.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Physics and Character Consistency$q$, $q$Strong simulation of fluid motion, object interaction and consistent character appearance across a clip.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Extended Clip Length$q$, $q$Generates clips up to 15 seconds long, longer than many competing video models.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Kling API$q$, $q$Developer-facing API for integrating video generation into third-party creative and marketing tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Credit-Based Subscription Tiers$q$, $q$Five pricing tiers from Free to Ultra, each providing a different monthly generation-credit allowance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Longer clip lengths and higher resolution output than many competing video models$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Strong physics simulation and character consistency noted across reviews$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Rapid iteration pace, with Kling 3.0 adding director-style multi-shot generation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Free tier available for testing before committing to a paid plan$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Developer API available for integrating generation into other products$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Credits expire monthly and do not roll over, penalizing inconsistent usage$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Highest tier (Ultra) is expensive at 180 dollars per month with no annual discount$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Free tier has limited daily credits and queue priority$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Introductory discounts apply only to the first billing cycle before reverting to standard rates$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Rapid version changes can make feature and pricing comparisons quickly outdated$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Who develops Kling AI?$q$, $q$Kling AI is developed by Kuaishou Technology, the Chinese short-video company headquartered in Beijing and listed on the Hong Kong Stock Exchange.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$When did Kling AI launch?$q$, $q$Kling AI launched publicly in June 2024, with major updates including Kling 3.0 in February 2026 and Kling 3.0 Turbo and Omni in June 2026.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$How much does Kling AI cost?$q$, $q$Kling AI offers a free tier plus paid plans starting at 6.99 dollars per month for Standard, up to 180 dollars per month for the Ultra tier.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$What is Kling 3.0's multi-shot generation?$q$, $q$It lets a single prompt generate up to six distinct shots with different framing and camera movement within one clip, while automatically maintaining spatial and character continuity.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Does Kling AI have an API?$q$, $q$Yes, Kuaishou offers a developer-facing Kling API for integrating video generation into third-party applications.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$How does Kling AI compare to Runway or Sora?$q$, $q$Kling AI is frequently noted for longer clip lengths, strong physics simulation and, since Kling 3.0, multi-shot director-style generation, competing directly with Runway, OpenAI's Sora, Google's Veo and others.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Social Media Video Content$q$, $q$Creators generate short, high-motion video clips from text prompts for social platforms without filming equipment.$q$, $q$Social video creators and influencers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Marketing and Advertising Video Production$q$, $q$Agencies produce quick concept videos and ad creative variations without traditional production crews.$q$, $q$Marketing teams and advertising agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$AI-Assisted Filmmaking$q$, $q$Independent filmmakers use multi-shot generation to storyboard and produce short narrative sequences from prompts.$q$, $q$Independent filmmakers and video producers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["Limited daily generation credits (~66/day)","Standard queue priority","Core text-to-video and image-to-video access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Standard$q$, $q$$6.99/month$q$, $q$Monthly (annual billing available at a discount)$q$, NULL, $q$["Increased monthly credit allowance","Improved generation priority over Free tier"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Pro$q$, $q$$25.99/month$q$, $q$Monthly (annual billing available at a discount)$q$, NULL, $q$["Higher monthly credit allowance","Faster generation priority"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Premier$q$, $q$$64.99/month$q$, $q$Monthly (annual billing available at a discount)$q$, NULL, $q$["~8,000 monthly credits","Aimed at studios and high-frequency creators"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$Ultra$q$, $q$$180/month$q$, $q$Monthly only$q$, NULL, $q$["~26,000 monthly credits","Highest generation priority","No standard queue limitations"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kling AI is a text-to-video and image-to-video generation platform developed by Kuaishou Technology, the Chinese short-video company headquartered in Beijing. The model was unveiled and launched publicly in June 2024, initially supporting videos up to two minutes long at 1080p resolution, a notably longer duration than most competing models at the time.$q$, $q$Kuaishou has iterated rapidly on the model since launch, releasing Kling 3.0 in February 2026 and Kling 3.0 Turbo and Omni variants in June 2026, adding native 4K output, up to 60fps frame rates, 15-second clip lengths, and multi-shot director-style generation that plans up to six distinct shots within a single output while maintaining continuity.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kling AI accepts both text prompts and reference images, generating short high-motion clips noted for realistic physics simulation and strong character consistency, historically weak points for earlier AI video models. The platform is available via web app, mobile apps, and a developer-facing API for programmatic integration.$q$, $q$Kling 3.0's multi-shot generation lets a single prompt produce an edited sequence of up to six shots, each with distinct framing and camera movement, while automatically preserving spatial and character continuity across cuts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kling AI uses a subscription-plus-credits model with five tiers: Free (limited daily credits), Standard at 6.99 dollars per month, Pro at 25.99 dollars per month, Premier at roughly 64.99 dollars per month, and Ultra at 180 dollars per month with the highest credit allowance and priority processing.$q$, $q$Annual billing offers a discount of roughly 20 to 34 percent on Standard, Pro and Premier, though Ultra is billed monthly only as of mid-2026. Credits expire at the end of each billing month and do not roll over.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
