INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d2a1121c-315f-4076-816c-d10e98925f90', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Visual Node-Based Workflow Builder$q$, $q$Drag-and-drop canvas for building data pipelines without writing code for most common tasks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Python, R and SQL Scripting Integration$q$, $q$Native scripting nodes let advanced users blend custom code with visual workflow design.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$ETL and Data Blending$q$, $q$Connect and combine data across databases, spreadsheets, cloud storage and APIs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Machine Learning and Statistics$q$, $q$Built-in nodes for classification, regression, clustering and classical statistical analysis.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Deep Learning Integration$q$, $q$Extensions connect to frameworks like Keras and TensorFlow for neural network workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Generative AI and LLM Nodes$q$, $q$Workflow nodes that call out to large language model providers as part of automated pipelines.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$KNIME Hub Collaboration$q$, $q$Sharing, versioning and scheduling of workflows for teams working beyond a single desktop.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Production Deployment (Business Hub)$q$, $q$REST API deployment of workflows as data apps or services, with governance and monitoring.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Full-featured desktop Analytics Platform is free and open source with no feature gating$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$No-code visual builder lowers the barrier to entry for non-programmers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Native support for blending Python, R, SQL and other code within visual workflows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Covers the full data science lifecycle from ETL through machine learning to deployment$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Large, established user community of 300,000+ across more than 60 countries$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Enterprise Business Hub pricing is not publicly disclosed and requires contacting sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Java/Eclipse-based desktop interface can feel dated compared to modern cloud-native tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Steeper learning curve for very large or complex workflows compared to code-first tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Production deployment and governance features require a separate paid Hub tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Less native cloud-first collaboration experience than competitors like Dataiku$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Is KNIME free to use?$q$, $q$Yes, the KNIME Analytics Platform is completely free and open source with full workflow-building capability and no feature gating.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$When was KNIME founded?$q$, $q$KNIME originated in January 2004 as a research project at the University of Konstanz, Germany, led by Michael Berthold, with its first public release in 2006.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Where is KNIME headquartered?$q$, $q$KNIME AG is headquartered in Zurich, Switzerland, with additional offices in Konstanz and Berlin, Germany, and Austin, Texas.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Does KNIME require coding skills?$q$, $q$No, KNIME is a no-code/low-code visual workflow builder, though it also supports native Python, R, SQL and Java scripting for advanced users.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$What is the difference between KNIME Analytics Platform and Business Hub?$q$, $q$The Analytics Platform is the free desktop workflow builder, while Business Hub is a paid enterprise layer for production deployment, scheduling, collaboration and governance.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$How does KNIME compare to Alteryx?$q$, $q$KNIME's core platform is free and open source, while Alteryx is a commercial, typically higher-priced no-code data-blending platform aimed at business analysts.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Data Blending and ETL Automation$q$, $q$Analysts combine and clean data from multiple databases and file sources without writing custom ETL code.$q$, $q$Data analysts and business intelligence teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Machine Learning Model Development$q$, $q$Data scientists build and test classification, regression and clustering models visually, blending in custom Python or R code as needed.$q$, $q$Data scientists and machine learning practitioners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$Production Data Pipeline Deployment$q$, $q$Organizations deploy analyst-built workflows as scheduled jobs or REST API services using KNIME Business Hub.$q$, $q$Enterprise data teams and IT operations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$KNIME Analytics Platform$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full visual workflow-building capability","No-code and low-code data pipeline design","Python, R, SQL and Java scripting integration","Machine learning, statistics and deep learning nodes","Open source under GPLv3"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$KNIME Community Hub Pro$q$, $q$Reportedly ~$19/month$q$, $q$Monthly$q$, NULL, $q$["Individual workflow scheduling","Basic collaboration features","Cloud-hosted workflow storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$KNIME Community Hub Team$q$, $q$Reportedly ~$99/month$q$, $q$Monthly, for small teams (e.g. 3 users)$q$, NULL, $q$["Team collaboration and sharing","Workflow scheduling for multiple users","Shared workspace management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$KNIME Business Hub$q$, $q$Custom pricing$q$, $q$Contact sales$q$, NULL, $q$["Production workflow deployment as data apps or services","Governance, permissions and monitoring","REST API deployment","Enterprise support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$KNIME originated in January 2004 as a research project at the University of Konstanz in Germany, led by Michael Berthold, with its first public open-source release following in 2006. The commercial entity KNIME AG is headquartered in Zurich, Switzerland, with additional offices in Konstanz and Berlin, Germany, and Austin, Texas.$q$, $q$KNIME's core product, the Analytics Platform, is a free, open-source, no-code visual workflow tool built on Java and the Eclipse Rich Client Platform, released under the GPLv3 license, used by a reported community of more than 300,000 users across over 60 countries.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users build data pipelines by dragging and connecting nodes on a canvas, covering ETL, data blending, cleaning, statistics, machine learning, deep learning integration, text mining and network analysis, without needing to write code for most tasks. Native scripting nodes for Python, R, SQL and Java let advanced users blend code with visual workflow design.$q$, $q$More recently, KNIME has added generative AI and large language model integration nodes, letting workflows call out to LLM providers as part of an automated pipeline. Beyond the desktop platform, KNIME Hub and Business Hub add collaboration, scheduling, versioning, REST API deployment and governance for production use.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9219abcb-3647-48e3-8c71-39e48254dcdb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The KNIME Analytics Platform is completely free and open source with full workflow-building capability and no feature gating. KNIME Community Hub adds lightweight team and scheduling features at modest reported monthly tiers, around 19 dollars per month for individual access and roughly 99 dollars per month for small teams.$q$, $q$The enterprise-grade KNIME Business Hub is sold on a custom quote basis for organizations needing production deployment and governance, with third-party marketplace listings showing list prices of several thousand dollars per month for the software license alone, excluding infrastructure costs.$q$]::text[], 2);
